sys_script_include.script:
var discordNotification = Class.create();
discordNotification.prototype = {
    initialize: function() {
		this.webhookUrl = gs.getProperty("x_1759267_wrm.discord.webhook_url");
    },
	sendMessage: function(message, emoji) {
		try {

			// Instantiate request with Discord API channel webhook
			var request = new sn_ws.RESTMessageV2(); 
			request.setEndpoint(this.webhookUrl);
			request.setHttpMethod('POST');
			request.setRequestHeader('Content-Type', 'application/json');

			var payload = { content: `${emoji} ${message}` }; 
			request.setRequestBody(JSON.stringify(payload)); 

			request.execute();

			gs.info("Discord | Status Code: " + response.getStatusCode());
			return(response.getStatusCode());

		} catch(err) {
			gs.error("Discord | Error: " + err.message);
			return '';
		}
	}, 
    type: 'discordNotification'
};
